def safe_divide(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        return None


def safe_index(lst, idx, default=None):
    try:
        return lst[idx]
    except IndexError:
        return default


def safe_key(d, key, default=None):
    try:
        return d[key]
    except KeyError:
        return default


def validate_input(value, expected_type):
    if isinstance(value, expected_type):
        return (True, 'valid')
    return (False, 'expected ' + expected_type.__name__ + ', got ' + type(value).__name__)
